INSERT INTO artists (id, name, slug, aliases, bio, socials) VALUES
  ('b0000000-0000-0000-0000-000000000001', 'Amelie Lens', 'amelie-lens', '{}', 'Belgian techno DJ and producer known for driving, energetic sets.', '{"instagram": "amelielens", "soundcloud": "amelielens"}'),
  ('b0000000-0000-0000-0000-000000000002', 'Four Tet', 'four-tet', '{"Kieran Hebden", "KH", "Percussions"}', 'British electronic musician known for eclectic, textured DJ sets spanning genres.', '{"instagram": "fourtetkieran", "soundcloud": "four-tet"}'),
  ('b0000000-0000-0000-0000-000000000003', 'Charlotte de Witte', 'charlotte-de-witte', '{}', 'Belgian techno DJ and label head of KNTXT.', '{"instagram": "charlottedewittemusic", "soundcloud": "charlottedewittemusic"}'),
  ('b0000000-0000-0000-0000-000000000004', 'Hardwell', 'hardwell', '{"Robbert van de Corput"}', 'Dutch DJ and producer, one of the biggest names in EDM and hardstyle crossover.', '{"instagram": "hardwell", "soundcloud": "hardwell"}'),
  ('b0000000-0000-0000-0000-000000000005', 'Martin Garrix', 'martin-garrix', '{"Martijn Garritsen", "YTRAM", "GRX"}', 'Dutch DJ and producer known for festival anthems and progressive house.', '{"instagram": "martingarrix", "soundcloud": "martingarrix"}'),
  ('b0000000-0000-0000-0000-000000000006', 'Peggy Gou', 'peggy-gou', '{}', 'South Korean DJ and producer blending house, techno, and electro.', '{"instagram": "peggygou_", "soundcloud": "peggygou"}'),
  ('b0000000-0000-0000-0000-000000000007', 'Armin van Buuren', 'armin-van-buuren', '{"Rising Star", "Gaia"}', 'Dutch trance DJ and five-time #1 DJ in the world.', '{"instagram": "arminvanbuuren", "soundcloud": "arminvanbuuren"}'),
  ('b0000000-0000-0000-0000-000000000008', 'Tiesto', 'tiesto', '{"Tijs Verwest"}', 'Dutch DJ and producer, pioneer of trance turned house music icon.', '{"instagram": "tiesto", "soundcloud": "tiesto"}'),
  ('b0000000-0000-0000-0000-000000000009', 'Bicep', 'bicep', '{}', 'Northern Irish electronic duo known for melodic house and breakbeat.', '{"instagram": "feelbicep", "soundcloud": "feelbicep"}'),
  ('b0000000-0000-0000-0000-000000000010', 'David Guetta', 'david-guetta', '{}', 'French DJ and producer, one of the best-selling electronic artists worldwide.', '{"instagram": "davidguetta", "soundcloud": "davidguetta"}'),
  ('b0000000-0000-0000-0000-000000000011', 'Adam Beyer', 'adam-beyer', '{}', 'Swedish techno DJ and Drumcode label boss.', '{"instagram": "realadambeyer", "soundcloud": "adambeyer"}'),
  ('b0000000-0000-0000-0000-000000000012', 'Calvin Harris', 'calvin-harris', '{"Adam Wiles", "Love Regenerator"}', 'Scottish DJ and producer, highest-paid DJ for multiple years.', '{"instagram": "calvinharris", "soundcloud": "calvinharris"}'),
  ('b0000000-0000-0000-0000-000000000013', 'Fred Again..', 'fred-again', '{"Fred Gibson"}', 'British producer and DJ known for sampling voice notes and live emotional sets.', '{"instagram": "fredagainagainagainagainagain", "soundcloud": "fredagain"}'),
  ('b0000000-0000-0000-0000-000000000014', 'Headhunterz', 'headhunterz', '{"Willem Rebergen"}', 'Dutch hardstyle DJ and producer, one of the genres most iconic artists.', '{"instagram": "headhunterz", "soundcloud": "headhunterz"}'),
  ('b0000000-0000-0000-0000-000000000015', 'Brennan Heart', 'brennan-heart', '{"Fabian Bohn"}', 'Dutch hardstyle DJ, producer, and I AM HARDSTYLE label founder.', '{"instagram": "brennanheart", "soundcloud": "brennanheart"}');
